<template >
    <div id = "app" >
        <div class = "files content" >
            <div v-if = "files['windows']" class = "files-wrp" >
                <p class = "summ" >Windows</p >
                <div class = "file-list" >
                    <file v-for = "(item, key) in files['windows']"
                          :key = "key"
                          :elem = "item"
                          os = "windows"
                          class = "file-list__itm" ></file >
                </div >
            </div >

            <div v-if = "files['linux']" class = "files-wrp" >
                <p class = "summ" >Linux-системы</p >
                <div class = "file-list" >
                    <file v-for = "(item, key) in files['linux']"
                          :key = "key"
                          :elem = "item"
                          os = "linux"
                          class = "file-list__itm" ></file >
                </div >
            </div >

            <div v-if = "files['macOS']" class = "files-wrp" >
                <p class = "summ" >macOS</p >
                <div class = "file-list" >
                    <file v-for = "(item, key) in files['macOS']"
                          :key = "key"
                          :elem = "item"
                          os = "macOS"
                          class = "file-list__itm" ></file >
                </div >
            </div >
        </div >
        <notes></notes>
    </div >
</template >

<script >
  import axios from "axios";
  import file from "./components/file.vue";
  import notifications from "./components/notifications";


  export default {
    name: "downloads",
    data() {
      return {
        files: {},
      };
    },
    components: {
      file,
      notes: notifications,
    },
    methods: {
      getFiles: function () {
        axios.get(
            "./json/files.json",
            {
              headers: {
                "Content-Type": "application/json",
              },
            },
        ).then(response => {
          this.files = response.data;
        }).catch(error => console.error(error));
      },
    },
    mounted() {
      this.getFiles();
    },
  };
</script >

<style >
    @import url('https://fonts.googleapis.com/css2?family=PT+Sans:ital,wght@0,400;0,700;1,400;1,700&display=swap');
    @import "includes/styles/_reset.css";
    @import 'includes/styles/_typo.css';
    @import 'includes/styles/_template.css';


    .files {
        margin-top: 20px;
        margin-bottom: 20px;
        }

    .files-wrp:not(:last-child) {margin-bottom: 25px;}

    .files-wrp > p {margin-bottom: 20px;}

    .file-list {
        display: grid;
        grid-gap: 20px 15px;
        }


    @media (min-width: 992px) {
        .file-list {
            grid-template-columns: repeat(2, 1fr);
            }
        }
</style >
