<template >
    <div class = "file-itm" >
        <svg class = "file-ico" >
            <use v-if = "os == 'windows'" xlink:href = "../assets/systems.svg#windows" ></use >
            <use v-if = "os == 'linux'" xlink:href = "../assets/systems.svg#linux" ></use >
            <use v-if = "os == 'macOS'" xlink:href = "../assets/systems.svg#macOS" ></use >
        </svg >
        <p class = "file-name" v-html = "elem.name" ></p >
        <div class = "file-info" >
            <svg @click = "toggleInfo" class = "file-info__ico" >
                <use xlink:href = "../assets/icons.svg#info" ></use >
            </svg >
            <div class = "file-info__tooltip"
                 :class = "isFullInfo? '' : 'hidden'" >
                <p v-html = "elem.description" ></p >
                <i class = "arrow" data-popper-arrow ></i >
            </div >
        </div >
        <a :href = "elem.link" class = "file-link" >
            <svg >
                <use xlink:href = "../assets/icons.svg#download" ></use >
            </svg >
        </a >
    </div >
</template >

<script >
  import {createPopper} from "@popperjs/core";
  import preventOverflow from "@popperjs/core/dist/esm/modifiers/preventOverflow";
  import flip from "@popperjs/core/dist/esm/modifiers/flip";

  export default {
    name: "file",
    props: [
      "elem",
      "os",
    ],
    data() {
      return {
        isFullInfo: false,
      };
    },
    methods: {
      toggleInfo: function () {
        this.isFullInfo = !this.isFullInfo;
      },
    },
    mounted() {
      const button = this.$el.querySelector(".file-info .file-info__ico"),
          tooltip = this.$el.querySelector(".file-info .file-info__tooltip");

      createPopper(button, tooltip, {
        placement: "top",
        modifiers: [
          preventOverflow,
          flip,
          {
            name: "offset",
            options: {
              offset: [0, 15],
            },
          },
        ],
      });
    },
  };
</script >

<style scoped >
    .file-itm {
        display: flex;
        padding: 13px 15px;
        flex-flow: row nowrap;
        align-items: center;
        border-radius: 6px;
        background: #fff;
        box-shadow: 0 0 7px rgba(0, 0, 0, 0.05);
        transition: all .2s linear;
        }

    .file-itm:hover {box-shadow: 0 3px 12px rgba(0, 0, 0, 0.08);}

    .file-ico {
        display: block;
        width: 30px;
        height: 30px;
        flex-shrink: 0;
        margin-right: 15px;
        }

    .file-name {
        max-width: 295px;
        margin-right: auto;
        }

    .file-info {
        position: relative;
        margin-left: 15px;
        }

    .file-info .file-info__ico {
        display: block;
        width: 18px;
        height: 18px;
        color: #D9D9D9;
        transition: all .2s linear;
        cursor: pointer;
        }

    .file-info .file-info__ico:hover {color: #8C8C8C;}

    .file-info .file-info__tooltip {
        position: absolute;
        width: 340px;
        max-width: calc(100vw - 20px);
        padding: 10px 15px;
        border-radius: 6px;
        background-color: #FFFFFF;
        box-shadow: 0 3px 12px rgba(0, 0, 0, 0.08);
        opacity: 1;
        transform: scale(1);
        z-index: 1;
        transition: opacity .2s linear;
        }

    .file-info .file-info__tooltip.hidden {
        opacity: 0;
        transform: scale(0);
        z-index: -1;
        }

    .file-info .file-info__tooltip > .arrow {
        position: absolute;
        display: block;
        width: 18px;
        height: 9px;
        border: 9px solid transparent;
        z-index: 1;
        }

    .file-info .file-info__tooltip[data-popper-placement^='top'] > .arrow {
        top: 100%;
        border: 9px solid transparent;
        border-bottom: 0;
        border-top-color: #fff;
        }

    .file-info .file-info__tooltip[data-popper-placement^='bottom'] > .arrow {
        bottom: 100%;
        border-top: 0;
        border-bottom-color: #fff;
        }

    .file-link {
        --c1: #454242;
        --c2: #454242;

        display: block;
        width: 32px;
        height: 32px;
        padding: 2px;
        flex-shrink: 0;
        margin-left: 11px;
        background-color: #FEDD46;
        border-radius: 6px;
        transition: all .2s linear;
        }

    .file-link:hover {
        background-color: #FFD516;
        }

    .file-link svg {
        display: block;
        width: 100%;
        height: 100%;
        }

    @media (max-width: 575px) {
        .file-ico {display: none !important;}
        }
</style >